mapper.update:
UPDATE favorite_info
SET
    canceled = #{canceled},
    update_time = #{updateTime},
    deleted = #{deleted}
WHERE favorite_id = #{favoriteId}

mapper.select:
SELECT COUNT(1)
FROM favorite_info
WHERE resource_id = #{resourceId}
  AND resource_type = #{resourceType}
  AND canceled = 0
  AND deleted = 0

SELECT resource_id
FROM favorite_info
WHERE user_id = #{userId}
  AND resource_type = #{resourceType}
  AND canceled = 0
  AND deleted = 0
ORDER BY update_time DESC, favorite_id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(1)
FROM favorite_info
WHERE user_id = #{userId}
  AND resource_type = #{resourceType}
  AND canceled = 0
  AND deleted = 0
